import{_ as a,o as i,c as o,ag as n}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"INFORMACIÓN DEL PLUGIN","description":"","frontmatter":{},"headers":[],"relativePath":"maxclear/funciones.md","filePath":"maxclear/funciones.md"}'),t={name:"maxclear/funciones.md"};function d(r,e,s,l,c,u){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="informacion-del-plugin" tabindex="-1">INFORMACIÓN DEL PLUGIN <a class="header-anchor" href="#informacion-del-plugin" aria-label="Permalink to &quot;INFORMACIÓN DEL PLUGIN&quot;">​</a></h1><blockquote><p>MaxClear es un plugin diseñado para optimizar el rendimiento de servidores de Minecraft, eliminando entidades innecesarias y controlando la generación de criaturas para prevenir el lag.</p></blockquote><h2 id="_1-optimizacion-automatica-de-entidades" tabindex="-1">1. Optimización Automática de Entidades <a class="header-anchor" href="#_1-optimizacion-automatica-de-entidades" aria-label="Permalink to &quot;1. Optimización Automática de Entidades&quot;">​</a></h2><blockquote><p>El núcleo del plugin está diseñado para mantener el servidor limpio de forma autónoma:</p></blockquote><ul><li><code>Limpieza Programada:</code> Realiza limpiezas automáticas en intervalos configurables (por defecto cada 5 minutos).</li><li><code>Sistema de Alertas:</code> Notifica a los jugadores con mensajes de advertencia personalizables antes de cada limpieza para evitar la pérdida accidental de objetos.</li><li><code>Limpieza Manual:</code> Permite a los administradores forzar una limpieza inmediata en todos los mundos o en mundos específicos.</li></ul><h2 id="_2-control-de-granjas-por-chunk" tabindex="-1">2. Control de Granjas por Chunk <a class="header-anchor" href="#_2-control-de-granjas-por-chunk" aria-label="Permalink to &quot;2. Control de Granjas por Chunk&quot;">​</a></h2><blockquote><p>Un sistema preventivo diseñado para evitar el abuso de entidades en áreas reducidas:</p></blockquote><ul><li><code>Límites por Chunk:</code> Establece un número máximo de entidades permitidas por chunk para prevenir lag causado por granjas masivas.</li><li><code>Gestión de Spawns:</code> Cancela automáticamente la generación de criaturas si se supera el límite configurado, protegiendo el TPS del servidor.</li></ul><h2 id="_3-filtrado-inteligente-y-exclusiones" tabindex="-1">3. Filtrado Inteligente y Exclusiones <a class="header-anchor" href="#_3-filtrado-inteligente-y-exclusiones" aria-label="Permalink to &quot;3. Filtrado Inteligente y Exclusiones&quot;">​</a></h2><blockquote><p>Configuraciones detalladas para asegurar que solo se eliminen entidades innecesarias:</p></blockquote><ul><li><code>Lista de Exclusión:</code> Protege entidades importantes como Aldeanos, Jugadores, Marcos, Soportes de Armaduras y diferentes tipos de Minecarts.</li><li><code>Protección de Objetos Valiosos:</code> Opción para ignorar objetos con nombres personalizados (Nametags).</li><li><code>Radio de Protección del Spawn:</code> Permite definir una distancia mínima desde el spawn del mundo donde las entidades no serán eliminadas.</li></ul>',11)])])}const f=a(t,[["render",d]]);export{p as __pageData,f as default};
